import type { Dayjs } from "dayjs";

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { Interval } from "../utils/formatPeriodLabel.ts";

/**
 * Chart view modes for the cashflow visualization
 * - bar: Bar chart showing income vs costs
 * - line: Line chart showing balance progression
 */
export type ChartViewMode = "bar" | "line";

export type { Interval };

export type Currency = NonNullable<
  BwCashflowModel["getCashFlowAndBalanceStates"]["request"]["filtering"]["currency"]
>;

/**
 * Category sum for income or costs
 */
export type CategorySum = {
  category: string;
  amount: number;
};

/**
 * Balance state object from API
 */
export interface BalanceState {
  balance: number;
  date?: string;
}

/**
 * Cash flow interval from API response
 */
export type CashFlowInterval = {
  dateFrom: string;
  dateTo: string;
  costs: number;
  income: number;
  netChange: number;
  startedBalance?: BalanceState;
  finalBalance?: BalanceState;
  incomeCategorySum?: CategorySum[];
  costsCategorySum?: CategorySum[];
  transactionCount?: number;
  cumulativeCosts?: number;
  cumulativeIncome?: number;
  cumulativeNetChange?: number;
};

/**
 * Balance quality indicator
 */
export type BalanceQuality = "IMPORTED" | "DERIVED" | "CALCULATED";

/**
 * Balance point from API response
 */
export type BalancePoint = {
  balance: number;
  date?: string;
  balanceQuality?: BalanceQuality;
};

/**
 * Transformed data point for bar chart visualization
 */
export type BarChartDataPoint = {
  // Display label for the period
  period: string;
  // Unique identifier for synchronization (e.g., "2025-01-01_2025-01-31")
  periodKey: string;
  dateFrom: string;
  dateTo: string;
  income: number;
  costs: number;
  netChange: number;
  incomePlanned?: number;
  costsPlanned?: number;
  incomeCategories?: CategorySum[];
  costsCategories?: CategorySum[];
  transactionCount?: number;
};

/**
 * Transformed data point for line chart visualization
 */
export type LineChartDataPoint = {
  [key: string]: number | string | undefined;
  // ISO date string
  date: string;
  // Numeric timestamp for proper x-axis spacing
  timestamp: number;
  dateLabel: string;
  balance: number;
  // Link to corresponding bar chart period for synchronization
  periodKey: string;
  balanceQuality: BalanceQuality;
};

/**
 * Legend data for displaying current balance and account info
 */
export type LegendData = {
  /** Current total balance across all selected accounts */
  currentBalance: number | null;
  /** Currency code (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the data */
  bankAccountCount: number;
  /** Quality of the most recent balance point */
  balanceQuality?: BalanceQuality;
};

/**
 * Time period controls for navigating and selecting periods
 */
export type TimePeriodControlsType = {
  /** Currently selected day that determines the highlighted period */
  selectedDay: Dayjs;
  /** Select a specific day (from date picker). Optionally update interval atomically. */
  setPeriod: (day: Dayjs, newInterval?: Interval) => void;
  /** Navigate to previous period */
  goToPreviousPeriod: () => void;
  /** Navigate to next period */
  goToNextPeriod: () => void;
  /** Whether we can navigate to previous period (not at min date) */
  canGoToPreviousPeriod: boolean;
  /** Whether we can navigate to next period (not at max date) */
  canGoToNextPeriod: boolean;
  /** Minimum selectable date (from settings - oldest transaction) */
  maxDateRangeFrom: Dayjs;
  /** Maximum selectable date (current date + 5 months) */
  maxDateRangeTo: Dayjs;
};

/**
 * Context type for cashflow chart state and data
 */
export type CashflowChartContextType = {
  viewMode: ChartViewMode;
  setViewMode: (mode: ChartViewMode) => void;
  interval: Interval;
  setInterval: (interval: Interval) => void;
  barChartData: BarChartDataPoint[];
  lineChartData: LineChartDataPoint[];
  lineChartSegmentKeys: {
    calculatedSegmentKeys: string[];
    importedSegmentKeys: string[];
    derivedSegmentKeys: string[];
  };
  legendData: LegendData;
};

